set-variable.value:
@{
                try {
                    var token = (string)context.Variables["pii-msi-access-token"];
                    return string.IsNullOrEmpty(token) ? "empty" : "acquired";
                } catch {
                    return "failed";
                }
            }

@{
                var inputText = context.Variables.GetValueOrDefault<string>("piiInputContent", "");
                var language = context.Variables.GetValueOrDefault<string>("piiDetectionLanguage", "en");
                var documents = new JArray();
                var maxDocChars = 5000;
                var maxDocsTotal = 100;
                try {
                    var bodyObj = JObject.Parse(inputText);
                    var messages = bodyObj["messages"] as JArray;
                    if (messages != null) {
                        for (int i = 0; i < messages.Count && documents.Count < maxDocsTotal; i++) {
                            var content = messages[i]?["content"]?.ToString();
                            if (!string.IsNullOrWhiteSpace(content)) {
                                if (content.Length <= maxDocChars) {
                                    documents.Add(new JObject {
                                        {"text", content},
                                        {"id", i.ToString()},
                                        {"language", language}
                                    });
                                } else {
                                    int chunkIdx = 0;
                                    int pos = 0;
                                    while (pos < content.Length && documents.Count < maxDocsTotal) {
                                        int end = Math.Min(pos + maxDocChars, content.Length);
                                        if (end < content.Length) {
                                            int lastSpace = content.LastIndexOf(' ', end - 1, end - pos);
                                            if (lastSpace > pos) { end = lastSpace + 1; }
                                        }
                                        documents.Add(new JObject {
                                            {"text", content.Substring(pos, end - pos)},
                                            {"id", i + "_" + chunkIdx},
                                            {"language", language}
                                        });
                                        pos = end;
                                        chunkIdx++;
                                    }
                                }
                            }
                        }
                    }
                } catch { }
                if (documents.Count == 0) {
                    documents.Add(new JObject {
                        {"text", inputText},
                        {"id", "raw"},
                        {"language", language}
                    });
                }
                var result = new JObject {
                    {"documents", documents},
                    {"count", documents.Count}
                };
                return result.ToString(Newtonsoft.Json.Formatting.None);
            }

@{
                try {
                    var build = JObject.Parse(context.Variables.GetValueOrDefault<string>("piiDocumentBuildResult", "{\"count\":0}"));
                    return build["count"]?.ToString() ?? "0";
                } catch { return "0"; }
            }

send-request.set-body:
@{
                    var build = JObject.Parse(context.Variables["piiDocumentBuildResult"]);
                    var allDocs = (JArray)build["documents"];
                    int count = build["count"].Value<int>();
                    int start = 0;
                    int end = Math.Min(5, count);
                    var batchDocs = new JArray();
                    for (int i = start; i < end; i++) { batchDocs.Add(allDocs[i]); }
                    var excludedCategoriesJson = context.Variables.GetValueOrDefault<string>("piiExcludedCategories", "[]");
                    JArray excludedCategories;
                    try { excludedCategories = JArray.Parse(excludedCategoriesJson); } catch { excludedCategories = new JArray(); }
                    var request = new JObject();
                    request["kind"] = "PiiEntityRecognition";
                    request["parameters"] = new JObject {
                        {"modelVersion", "latest"},
                        {"redactionPolicy", new JObject { {"policyKind", "CharacterMask"}, {"redactionCharacter", "#"} }}
                    };
                    if (excludedCategories.Count > 0) { request["parameters"]["excludePiiCategories"] = excludedCategories; }
                    request["analysisInput"] = new JObject { {"documents", batchDocs} };
                    return request.ToString();
                }

set-variable.value:
@{
                try {
                    var resp = context.Variables.GetValueOrDefault<IResponse>("piiBatch0Response");
                    var code = resp != null ? ((int)resp.StatusCode).ToString() : "0";
                    if (code != "200") { return context.Variables.GetValueOrDefault<string>("piiRedactedMapJson", "{}"); }
                    var body = resp.Body.As<string>(preserveContent: true);
                    var jobj = JObject.Parse(body);
                    var docs = jobj.SelectToken("$.results.documents") as JArray;
                    var current = JObject.Parse(context.Variables.GetValueOrDefault<string>("piiRedactedMapJson", "{}"));
                    if (docs != null) { foreach (var d in docs) { var id = d["id"]?.ToString(); var rt = d["redactedText"]?.ToString(); if (id != null && rt != null) current[id] = rt; } }
                    return current.ToString(Newtonsoft.Json.Formatting.None);
                } catch { return context.Variables.GetValueOrDefault<string>("piiRedactedMapJson", "{}"); }
            }

@{
                try {
                    var r = context.Variables.GetValueOrDefault<IResponse>("piiBatch0Response");
                    return r != null ? ((int)r.StatusCode).ToString() : "0";
                } catch { return "0"; }
            }

@{
                try {
                    var r = context.Variables.GetValueOrDefault<IResponse>("piiBatch0Response");
                    if (r == null || ((int)r.StatusCode) != 200) return context.Variables.GetValueOrDefault<string>("piiAccumulatedEntityCount", "0");
                    var body = r.Body.As<string>(preserveContent: true);
                    var jobj = JObject.Parse(body);
                    var docs = jobj.SelectToken("$.results.documents") as JArray;
                    int sum = int.Parse(context.Variables.GetValueOrDefault<string>("piiAccumulatedEntityCount", "0"));
                    if (docs != null) foreach (var d in docs) { var ents = d["entities"] as JArray; sum += ents?.Count ?? 0; }
                    return sum.ToString();
                } catch { return context.Variables.GetValueOrDefault<string>("piiAccumulatedEntityCount", "0"); }
            }

@{
                try {
                    var r = context.Variables.GetValueOrDefault<IResponse>("piiBatch0Response");
                    if (r == null || ((int)r.StatusCode) != 200) return context.Variables.GetValueOrDefault<string>("piiAccumulatedEntityTypes", "");
                    var body = r.Body.As<string>(preserveContent: true);
                    var jobj = JObject.Parse(body);
                    var docs = jobj.SelectToken("$.results.documents") as JArray;
                    var set = new System.Collections.Generic.HashSet<string>();
                    foreach (var s in (context.Variables.GetValueOrDefault<string>("piiAccumulatedEntityTypes", "") ?? "").Split(new[] { ',' }, StringSplitOptions.RemoveEmptyEntries)) set.Add(s.Trim());
                    if (docs != null) foreach (var d in docs) { var ents = d["entities"] as JArray; if (ents != null) foreach (var e in ents) { var c = e["category"]?.ToString(); if (c != null) set.Add(c); } }
                    return string.Join(",", set);
                } catch { return context.Variables.GetValueOrDefault<string>("piiAccumulatedEntityTypes", ""); }
            }

@{
                try {
                    var r = context.Variables.GetValueOrDefault<IResponse>("piiBatch0Response");
                    if (r == null || ((int)r.StatusCode) != 200) return context.Variables.GetValueOrDefault<string>("piiAccumulatedDocErrors", "");
                    var body = r.Body.As<string>(preserveContent: true);
                    var jobj = JObject.Parse(body);
                    var errs = jobj.SelectToken("$.results.errors") as JArray;
                    var prev = context.Variables.GetValueOrDefault<string>("piiAccumulatedDocErrors", "");
                    if (errs == null || errs.Count == 0) return prev;
                    var list = new System.Collections.Generic.List<string>();
                    if (!string.IsNullOrEmpty(prev)) list.Add(prev);
                    foreach (var err in errs) { var id = err["id"]?.ToString() ?? "?"; var msg = err.SelectToken("$.error.message")?.ToString() ?? "unknown"; list.Add("doc-" + id + ":" + msg); }
                    return string.Join("; ", list);
                } catch { return context.Variables.GetValueOrDefault<string>("piiAccumulatedDocErrors", ""); }
            }

send-request.set-body:
@{
                            var build = JObject.Parse(context.Variables["piiDocumentBuildResult"]);
                            var allDocs = (JArray)build["documents"];
                            int count = build["count"].Value<int>();
                            int start = 5, end = Math.Min(10, count);
                            var batchDocs = new JArray();
                            for (int i = start; i < end; i++) { batchDocs.Add(allDocs[i]); }
                            var excludedCategoriesJson = context.Variables.GetValueOrDefault<string>("piiExcludedCategories", "[]");
                            JArray excludedCategories;
                            try { excludedCategories = JArray.Parse(excludedCategoriesJson); } catch { excludedCategories = new JArray(); }
                            var request = new JObject {
                                {"kind", "PiiEntityRecognition"},
                                {"parameters", new JObject {
                                    {"modelVersion", "latest"},
                                    {"redactionPolicy", new JObject { {"policyKind", "CharacterMask"}, {"redactionCharacter", "#"} }}
                                }},
                                {"analysisInput", new JObject { {"documents", batchDocs} }}
                            };
                            if (excludedCategories.Count > 0) { request["parameters"]["excludePiiCategories"] = excludedCategories; }
                            return request.ToString();
                        }

