@{
                try {
                    var startTicks = long.Parse(context.Variables.GetValueOrDefault<string>("piiStartTimeTicks", DateTime.UtcNow.Ticks.ToString()));
                    return ((DateTime.UtcNow.Ticks - startTicks) / TimeSpan.TicksPerMillisecond).ToString();
                } catch {
                    return "-1";
                }
            }

@{
                try {
                    if (context.Variables.GetValueOrDefault<string>("piiAnyBatchFailed", "false") == "true") { return "false"; }
                    var statusCode = context.Variables.GetValueOrDefault<string>("piiDetectionStatusCode", "0");
                    if (statusCode != "200") { return "false"; }
                    var mapStr = context.Variables.GetValueOrDefault<string>("piiRedactedMapJson", "{}");
                    var map = JObject.Parse(mapStr);
                    return (map.Count > 0).ToString().ToLower();
                } catch {
                    return "false";
                }
            }

@{
                try {
                    var statusCode = context.Variables.GetValueOrDefault<string>("piiDetectionStatusCode", "0");
                    if (statusCode != "200") {
                        return new JObject {{"fullCoverage",true},{"msgsWithContent",0},{"msgsRedacted",0},{"msgsPartial",0},{"msgsUnscanned",0}}.ToString(Newtonsoft.Json.Formatting.None);
                    }
                    var mapStr = context.Variables.GetValueOrDefault<string>("piiRedactedMapJson", "{}");
                    var redactedMap = JObject.Parse(mapStr);
                    var inputText = context.Variables.GetValueOrDefault<string>("piiInputContent", "");
                    var bodyObj = JObject.Parse(inputText);
                    var messages = bodyObj["messages"] as JArray;
                    int msgsWithContent = 0;
                    int msgsRedacted = 0;
                    int msgsPartial = 0;
                    int msgsUnscanned = 0;
                    if (messages != null) {
                        for (int i = 0; i < messages.Count; i++) {
                            var content = messages[i]?["content"]?.ToString();
                            if (string.IsNullOrWhiteSpace(content)) { continue; }
                            msgsWithContent++;
                            if (redactedMap.ContainsKey(i.ToString())) {
                                msgsRedacted++;
                            } else if (redactedMap.ContainsKey(i + "_0")) {
                                int totalChunkLen = 0;
                                int chunkIdx = 0;
                                while (redactedMap.ContainsKey(i + "_" + chunkIdx)) {
                                    totalChunkLen += redactedMap[i + "_" + chunkIdx].ToString().Length;
                                    chunkIdx++;
                                }
                                if (totalChunkLen >= content.Length) {
                                    msgsRedacted++;
                                } else {
                                    msgsPartial++;
                                }
                            } else {
                                msgsUnscanned++;
                            }
                        }
                    }
                    return new JObject {
                        {"msgsWithContent", msgsWithContent},
                        {"msgsRedacted", msgsRedacted},
                        {"msgsPartial", msgsPartial},
                        {"msgsUnscanned", msgsUnscanned},
                        {"fullCoverage", (msgsRedacted == msgsWithContent)}
                    }.ToString(Newtonsoft.Json.Formatting.None);
                } catch {
                    return new JObject {{"fullCoverage",true},{"msgsWithContent",0},{"msgsRedacted",0},{"msgsPartial",0},{"msgsUnscanned",0}}.ToString(Newtonsoft.Json.Formatting.None);
                }
            }

when.condition:
@{
                    if (context.Variables.GetValueOrDefault<string>("piiFailClosed", "false").ToLower() != "true") { return false; }
                    if (context.Variables.GetValueOrDefault<string>("piiRedactionSucceeded", "false") == "false") { return true; }
                    try {
                        var cov = JObject.Parse(context.Variables.GetValueOrDefault<string>("piiRedactionCoverage", "{}"));
                        return !(cov["fullCoverage"]?.Value<bool>() ?? true);
                    } catch { return false; }
                }

return-response.set-body:
@{
                            var piiStatus = context.Variables.GetValueOrDefault<string>("piiDetectionStatusCode", "unknown");
                            var duration = context.Variables.GetValueOrDefault<string>("piiDurationMs", "unknown");
                            var msi = context.Variables.GetValueOrDefault<string>("piiMsiTokenStatus", "unknown");
                            var coverageJson = context.Variables.GetValueOrDefault<string>("piiRedactionCoverage", "{}");
                            string failureReason;
                            if (context.Variables.GetValueOrDefault<string>("piiRedactionSucceeded", "false") == "false") {
                                if (msi == "failed" || msi == "empty") { failureReason = "msi-token-" + msi; }
                                else if (piiStatus == "no-response") { failureReason = "network-or-dns-error"; }
                                else if (piiStatus == "error") { failureReason = "response-read-error"; }
                                else if (piiStatus != "200") { failureReason = "http-error-" + piiStatus; }
                                else { failureReason = "parse-error"; }
                            } else {
                                try {
                                    var cov = JObject.Parse(coverageJson);
                                    var unscanned = cov["msgsUnscanned"]?.Value<int>() ?? 0;
                                    var partial = cov["msgsPartial"]?.Value<int>() ?? 0;
                                    if (unscanned > 0) { failureReason = "partial-redaction-" + unscanned + "-msgs-unscanned"; }
                                    else if (partial > 0) { failureReason = "partial-redaction-" + partial + "-msgs-truncated"; }
                                    else { failureReason = "partial-redaction-unknown"; }
                                } catch { failureReason = "coverage-check-error"; }
                            }
                            string message;
                            if (failureReason.StartsWith("partial-redaction")) {
                                message = "PII redaction incomplete. Not all messages were scanned. Request blocked for data protection.";
                            } else {
                                message = "PII redaction service is unavailable. Request blocked for data protection.";
                            }
                            var errorResponse = new JObject {
                                {"error", new JObject {
                                    {"code", "PiiRedactionUnavailable"},
                                    {"message", message},
                                    {"request_id", context.RequestId.ToString()},
                                    {"pii_status_code", piiStatus},
                                    {"pii_duration_ms", duration},
                                    {"failure_reason", failureReason},
                                    {"coverage", JObject.Parse(coverageJson)}
                                }}
                            };
                            return errorResponse.ToString();
                        }

set-variable.value:
@{
                try {
                    var statusCode = context.Variables.GetValueOrDefault<string>("piiDetectionStatusCode", "0");
                    if (statusCode != "200") {
                        return context.Variables.GetValueOrDefault<string>("piiInputContent", "");
                    }
                    var mapStr = context.Variables.GetValueOrDefault<string>("piiRedactedMapJson", "{}");
                    var redactedMap = JObject.Parse(mapStr);
                    if (redactedMap.ContainsKey("raw")) {
                        return redactedMap["raw"].ToString();
                    }
                    var inputText = context.Variables.GetValueOrDefault<string>("piiInputContent", "");
                    var bodyObj = JObject.Parse(inputText);
                    var messages = bodyObj["messages"] as JArray;
                    if (messages != null) {
                        for (int i = 0; i < messages.Count; i++) {
                            var key = i.ToString();
                            if (redactedMap.ContainsKey(key)) {
                                ((JObject)messages[i])["content"] = redactedMap[key].ToString();
                            } else {
                                var sb = new System.Text.StringBuilder();
                                int chunkIdx = 0;
                                while (redactedMap.ContainsKey(i + "_" + chunkIdx)) {
                                    sb.Append(redactedMap[i + "_" + chunkIdx].ToString());
                                    chunkIdx++;
                                }
                                if (chunkIdx > 0) {
                                    var originalContent = messages[i]?["content"]?.ToString() ?? "";
                                    if (sb.Length >= originalContent.Length) {
                                        ((JObject)messages[i])["content"] = sb.ToString();
                                    }
                                }
                            }
                        }
                    }
                    return bodyObj.ToString(Newtonsoft.Json.Formatting.None);
                } catch {
                    return context.Variables.GetValueOrDefault<string>("piiInputContent", "");
                }
            }

@{
                try {
                    var statusCode = context.Variables.GetValueOrDefault<string>("piiDetectionStatusCode", "0");
                    if (statusCode != "200") {
                        return "{}";
                    }
                    int docCount = int.Parse(context.Variables.GetValueOrDefault<string>("piiTotalDocs", "0"));
                    int totalEntities = int.Parse(context.Variables.GetValueOrDefault<string>("piiAccumulatedEntityCount", "0"));
                    var categories = context.Variables.GetValueOrDefault<string>("piiAccumulatedEntityTypes", "") ?? "";
                    var docErrors = context.Variables.GetValueOrDefault<string>("piiAccumulatedDocErrors", "") ?? "";
                    var result = new JObject {
                        {"docCount", docCount},
                        {"docErrors", string.IsNullOrEmpty(docErrors) ? "none" : docErrors},
                        {"entityCount", totalEntities},
                        {"entityTypes", string.IsNullOrEmpty(categories) ? "none" : categories}
                    };
                    try {
                        var covJson = context.Variables.GetValueOrDefault<string>("piiRedactionCoverage", "{}");
                        var cov = JObject.Parse(covJson);
                        result["msgsWithContent"] = cov["msgsWithContent"];
                        result["msgsRedacted"] = cov["msgsRedacted"];
                        result["msgsPartial"] = cov["msgsPartial"];
                        result["msgsUnscanned"] = cov["msgsUnscanned"];
                        result["fullCoverage"] = cov["fullCoverage"];
                    } catch { }
                    return result.ToString(Newtonsoft.Json.Formatting.None);
                } catch (Exception ex) {
                    return "{}";
                }
            }

@{
                try {
                    var inputText = context.Variables.GetValueOrDefault<string>("piiInputContent", "");
                    var anonymized = context.Variables.GetValueOrDefault<string>("piiAnonymizedContent", "");
                    return (!string.Equals(inputText, anonymized, System.StringComparison.Ordinal)).ToString();
                } catch {
                    return "error";
                }
            }
